import{_ as t,o as a,c as i,ag as s}from"./chunks/framework.CvgP6Fyv.js";const h=JSON.parse('{"title":"AI Features","description":"","frontmatter":{},"headers":[],"relativePath":"advanced/ai-features.md","filePath":"advanced/ai-features.md"}'),o={name:"advanced/ai-features.md"};function r(n,e,l,c,u,d){return a(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="ai-features" tabindex="-1">AI Features <a class="header-anchor" href="#ai-features" aria-label="Permalink to &quot;AI Features&quot;">​</a></h1><p>MyCompanyDesk includes AI-powered features to help you work faster and smarter.</p><h2 id="contextual-guide" tabindex="-1">Contextual guide <a class="header-anchor" href="#contextual-guide" aria-label="Permalink to &quot;Contextual guide&quot;">​</a></h2><p>The in-app assistant helps you navigate MyCompanyDesk:</p><ul><li>Click the <strong>help icon</strong> on any page for context-aware help</li><li>Ask questions about features, workflows, or settings</li><li>Get step-by-step guidance for common tasks</li><li>Available in all four supported languages</li></ul><p>The guide understands which page you&#39;re on and provides relevant suggestions.</p><h3 id="chat-limits" tabindex="-1">Chat limits <a class="header-anchor" href="#chat-limits" aria-label="Permalink to &quot;Chat limits&quot;">​</a></h3><p>Chat usage depends on your plan:</p><table tabindex="0"><thead><tr><th>Plan</th><th>Chat messages</th></tr></thead><tbody><tr><td>Free</td><td>Limited</td></tr><tr><td>Pro</td><td>Generous allowance</td></tr><tr><td>Business</td><td>Highest allowance</td></tr></tbody></table><h2 id="ai-suggestions" tabindex="-1">AI suggestions <a class="header-anchor" href="#ai-suggestions" aria-label="Permalink to &quot;AI suggestions&quot;">​</a></h2><p>Smart recommendations that help you categorize and describe your records:</p><h3 id="expense-categorization" tabindex="-1">Expense categorization <a class="header-anchor" href="#expense-categorization" aria-label="Permalink to &quot;Expense categorization&quot;">​</a></h3><p>When you create an expense, AI analyzes the description and suggests the most appropriate category. This saves time and ensures consistent categorization.</p><h3 id="description-improvements" tabindex="-1">Description improvements <a class="header-anchor" href="#description-improvements" aria-label="Permalink to &quot;Description improvements&quot;">​</a></h3><p>AI can suggest clearer, more professional descriptions for:</p><ul><li>Invoice line items</li><li>Expense descriptions</li><li>Customer notes</li></ul><h3 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h3><ol><li>Create or edit a record</li><li>Look for the AI suggestion indicator</li><li>Review the suggestion</li><li>Click <strong>Apply</strong> to use it, or <strong>Dismiss</strong> to skip</li></ol><div class="info custom-block"><p class="custom-block-title">INFO</p><p>AI suggestions require the <strong>Pro</strong> plan or higher. Enable them in <strong>Company &gt; Features</strong>.</p></div><h2 id="receipt-scanning" tabindex="-1">Receipt scanning <a class="header-anchor" href="#receipt-scanning" aria-label="Permalink to &quot;Receipt scanning&quot;">​</a></h2><p>AI-powered OCR extracts data from receipt images and PDFs:</p><ul><li><strong>Date</strong> — When the purchase was made</li><li><strong>Amount</strong> — Total cost</li><li><strong>Supplier</strong> — Who you paid</li><li><strong>Description</strong> — What was purchased</li></ul><p>See <a href="/advanced/receipt-scanning">Receipt Scanning</a> for detailed instructions.</p><h2 id="text-check" tabindex="-1">Text check <a class="header-anchor" href="#text-check" aria-label="Permalink to &quot;Text check&quot;">​</a></h2><p>Grammar and spelling checking for your documents:</p><ul><li>Check invoice descriptions before sending</li><li>Verify quote content</li><li>Fix typos in customer-facing text</li></ul><p>Supports English, Dutch, German, and French.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Text check requires the <strong>Pro</strong> plan or higher.</p></div><h2 id="account-summaries" tabindex="-1">Account summaries <a class="header-anchor" href="#account-summaries" aria-label="Permalink to &quot;Account summaries&quot;">​</a></h2><p>AI generates periodic summaries of your business activity:</p><ul><li><strong>Daily</strong> — Quick overview of the day&#39;s transactions</li><li><strong>Weekly</strong> — Week-in-review with trends</li><li><strong>Monthly</strong> — Comprehensive monthly analysis</li></ul><p>Summaries are generated in your preferred language and available from the dashboard.</p><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Enable AI suggestions once and they work automatically in the background</li><li>Receipt scanning is especially useful for paper receipts — just take a photo</li><li>The contextual guide can answer most &quot;how do I...&quot; questions about the app</li><li>AI features use privacy-respecting processing — your data stays secure</li></ul>',34)])])}const g=t(o,[["render",r]]);export{h as __pageData,g as default};
